class Solution:
    def totalSteps(self, nums):
        arr = list(nums)
        steps = 0
        while True:
            keep = [arr[0]] if arr else []
            removed = False
            for i in range(1, len(arr)):
                if arr[i - 1] > arr[i]:
                    removed = True
                else:
                    keep.append(arr[i])
            if not removed:
                return steps
            steps += 1
            arr = keep

