class Solution:
    def totalSteps(self, nums):
        stack = []
        ans = 0
        for v in nums:
            cur = 0
            while stack and stack[-1][0] <= v:
                cur = max(cur, stack.pop()[1])
            cur = cur + 1 if stack else 0
            ans = max(ans, cur)
            stack.append((v, cur))
        return ans

