var totalSteps = function(nums) {
    const stack = [];
    let ans = 0;
    for (const v of nums) {
        let cur = 0;
        while (stack.length && stack[stack.length - 1][0] <= v) {
            cur = Math.max(cur, stack.pop()[1]);
        }
        cur = stack.length ? cur + 1 : 0;
        ans = Math.max(ans, cur);
        stack.push([v, cur]);
    }
    return ans;
};
